:root {
  --bg: #f4f7fb;
  --text: #112033;
  --surface: #ffffff;
  --accent: #f3ad3b;
}

body {
  margin: 0;
  font-family: 'Segoe UI', sans-serif;
  background: var(--bg);
  color: var(--text);
}

.site-header,
main,
footer {
  width: min(860px, 92vw);
  margin-inline: auto;
}

.site-header {
  margin-top: 1.4rem;
  padding: 1rem 1.2rem;
  border-radius: 0.8rem;
  background: var(--surface);
}

nav {
  display: flex;
  gap: 0.8rem;
}

main {
  margin-top: 1rem;
  padding: 1rem 1.2rem;
  border-radius: 0.8rem;
  background: var(--surface);
}

button {
  border: 0;
  border-radius: 0.6rem;
  padding: 0.6rem 0.9rem;
  background: var(--accent);
  font-weight: 700;
  cursor: pointer;
}

const button = document.getElementById('theme-btn');

button?.addEventListener('click', () => {
  const root = document.documentElement;
  const isDark = root.dataset.theme === 'dark';

  if (isDark) {
    root.dataset.theme = '';
    root.style.setProperty('--bg', '#f4f7fb');
    root.style.setProperty('--text', '#112033');
    root.style.setProperty('--surface', '#ffffff');
    root.style.setProperty('--accent', '#f3ad3b');
    return;
  }

  root.dataset.theme = 'dark';
  root.style.setProperty('--bg', '#101a24');
  root.style.setProperty('--text', '#eef6ff');
  root.style.setProperty('--surface', '#172534');
  root.style.setProperty('--accent', '#ffc668');
});
